+#!/usr/bin/env -S gjs -m
+// Minimal test runner for GJS standalone
+
+let _passed = 0;
+let _failed = 0;
+let _currentSuite = '';
+
+export function describe(name, fn) {
+    _currentSuite = name;
+    print(`\n  ${name}`);
+    fn();
+    _currentSuite = '';
+}
+
+export function it(name, fn) {
+    try {
+        fn();
+        _passed++;
+        print(`    ✓ ${name}`);
+    } catch (e) {
+        _failed++;
+        print(`    ✗ ${name}`);
+        print(`      ${e.message}`);
+    }
+}
+
+export function assertEqual(actual, expected, msg = '') {
+    if (actual !== expected)
+        throw new Error(`${msg ? msg + ': ' : ''}expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
+}
+
+export function assertDeepEqual(actual, expected, msg = '') {
+    const a = JSON.stringify(actual);
+    const e = JSON.stringify(expected);
+    if (a !== e)
+        throw new Error(`${msg ? msg + ': ' : ''}expected ${e}, got ${a}`);
+}
+
+export function assertTrue(val, msg = '') {
+    if (!val)
+        throw new Error(`${msg ? msg + ': ' : ''}expected truthy, got ${JSON.stringify(val)}`);
+}
+
+export function assertFalse(val, msg = '') {
+    if (val)
+        throw new Error(`${msg ? msg + ': ' : ''}expected falsy, got ${JSON.stringify(val)}`);
+}
+
+export function assertNull(val, msg = '') {
+    if (val !== null)
+        throw new Error(`${msg ? msg + ': ' : ''}expected null, got ${JSON.stringify(val)}`);
+}
+
+export function assertThrows(fn, msg = '') {
+    try {
+        fn();
+        throw new Error(`${msg ? msg + ': ' : ''}expected function to throw`);
+    } catch (e) {
+        if (e.message.includes('expected function to throw'))
+            throw e;
+    }
+}
+
+export function printResults() {
+    print(`\n  ${_passed} passing, ${_failed} failing\n`);
+    return _failed === 0;
+}
